import json, sys, re, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool  = ev.get("tool_name", "")
    inp   = ev.get("tool_input") or {}
    resp  = ev.get("tool_response") or {}

    # Only run on Edit/Write to Python files
    if tool not in ("Edit", "Write"):
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Check if file exists and read it
    if not os.path.exists(file_path):
        return 0

    try:
        with open(file_path, 'r') as f:
            content = f.read()
    except Exception:
        return 0

    # Detect recursive function definitions
    # Pattern: def foo(...): ... foo(...)
    func_pattern = r'^\s*def\s+(\w+)\s*\([^)]*\):'

    functions = {}
    lines = content.split('\n')
    current_func = None
    current_indent = 0

    for i, line in enumerate(lines, 1):
        func_match = re.match(func_pattern, line)
        if func_match:
            current_func = func_match.group(1)
            current_indent = len(line) - len(line.lstrip())
            functions[current_func] = {'start_line': i, 'calls_self': False, 'indent': current_indent}
        elif current_func:
            # Check if we're still in the function
            if line.strip() and not line.strip().startswith('#'):
                line_indent = len(line) - len(line.lstrip())
                if line_indent <= current_indent:
                    current_func = None
                elif re.search(r'\b' + re.escape(current_func) + r'\s*\(', line):
                    functions[current_func]['calls_self'] = True

    # Find recursive functions
    recursive_funcs = [name for name, info in functions.items() if info['calls_self']]

    if recursive_funcs:
        func_list = ", ".join([f"{name} (line {functions[name]['start_line']})" for name in recursive_funcs])
        sys.stderr.write(
            f"REQUIRED FOLLOW-UP: Recursive function(s) detected in {os.path.basename(file_path)}: {func_list}. "
            f"This project had RecursionError failures with 2000-node trees. "
            f"Add explicit recursion depth limits or convert to iterative. "
            f"Do not stop until each recursive function has either: "
            f"(1) depth limit parameter with safe default, "
            f"(2) iterative rewrite, or "
            f"(3) documented proof that max depth < 1000. "
            f"Fix each, then summarize.\n"
        )
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
import json
import sys
import subprocess
import os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Only check Python files
    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Run ruff check on the modified file
    project_dir = os.environ.get("CLAUDE_PROJECT_DIR", "")
    if not project_dir:
        return 0

    try:
        result = subprocess.run(
            ["ruff", "check", file_path],
            cwd=project_dir,
            capture_output=True,
            text=True,
            timeout=10
        )

        if result.returncode != 0:
            # IMPERATIVE stderr per rubric criterion 12
            sys.stderr.write(
                f"REQUIRED FOLLOW-UP: ruff check found violations in {os.path.basename(file_path)}:\n"
                f"{result.stdout}\n"
                f"Fix each violation now, then continue. Do not stop until all violations are resolved.\n"
            )
            return 2

    except (subprocess.TimeoutExpired, FileNotFoundError):
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, subprocess, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool  = ev.get("tool_name", "")
    inp   = ev.get("tool_input")    or {}
    resp  = ev.get("tool_response") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    old_string = inp.get("old_string", "")
    new_string = inp.get("new_string", "")

    # Check if the file contains "export" keyword (signals exported identifiers)
    try:
        with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
            content = f.read()
            if 'export' not in content:
                return 0  # Not an export-heavy file
    except Exception:
        return 0

    # Extract string literals from old_string and new_string
    # Pattern: quoted strings like 'Read' or "Read"
    old_literals = re.findall(r'''['"]([^'"]+)['"]''', old_string)
    new_literals = re.findall(r'''['"]([^'"]+)['"]''', new_string)

    # Find literals that were changed (present in old but replaced in new)
    changed = []
    for old_lit in old_literals:
        if old_lit not in new_literals and len(old_lit) > 2:  # Skip very short strings
            changed.append(old_lit)

    if not changed:
        return 0  # No meaningful string changes

    # For each changed literal, grep for references
    cwd = ev.get("cwd", ".")
    findings = []

    for literal in changed:
        try:
            result = subprocess.run(
                ['rg', '--no-heading', '--line-number', '--type', 'ts', '--type', 'js', literal, cwd],
                capture_output=True,
                text=True,
                timeout=5
            )
            if result.returncode == 0 and result.stdout.strip():
                match_count = len(result.stdout.strip().split('\n'))
                findings.append(f"'{literal}': {match_count} references found\n{result.stdout[:500]}")
        except Exception:
            continue

    if findings:
        msg = f"REQUIRED FOLLOW-UP: Renamed exported identifier references detected.\n\n"
        msg += "\n\n".join(findings)
        msg += "\n\nUpdate each occurrence to the new value, then proceed. Do not stop until all references are fixed."
        print(msg, file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Write/Edit operations that would hardcode API keys, tokens, or other
secrets into source files; enforce CLAUDE.md rule: secrets come from env."""
import json, re, sys

# Patterns that look like secrets
SECRET_PATTERNS = [
    (r'\b(sk-[a-zA-Z0-9_-]{20,})', 'OpenAI API key'),
    (r'\b([a-zA-Z0-9_-]{20,}\.amazonaws\.com)', 'AWS endpoint with embedded creds'),
    (r'["\']?(api[_-]?key|apikey|api_secret|secret[_-]?key|access[_-]?token|bearer[_-]?token|password)["\']?\s*[:=]\s*["\']([a-zA-Z0-9_\-\/+=]{8,})["\']', 'API key/token/password assignment'),
    (r'\b(ghp_[a-zA-Z0-9]{36,}|github_pat_[a-zA-Z0-9_]{82})', 'GitHub personal access token'),
    (r'\b(AKIA[0-9A-Z]{16})', 'AWS access key ID'),
    (r'\b(ya29\.[a-zA-Z0-9_-]{50,})', 'Google OAuth token'),
]

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit"):
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    # Only check source files (not .env files, which SHOULD have secrets)
    if not file_path or file_path.endswith(('.env', '.env.local', '.env.production', '.env.example')):
        return 0

    # Common source extensions
    src_exts = ('.ts', '.tsx', '.js', '.jsx', '.py', '.go', '.java', '.rb', '.php', '.cs', '.cpp', '.c', '.h', '.sh')
    if not any(file_path.endswith(ext) for ext in src_exts):
        return 0

    # Collect content to scan
    content = ""
    if tool == "Write":
        content = inp.get("content", "")
    elif tool == "Edit":
        content = inp.get("new_string", "")

    if not content:
        return 0

    # Scan for secret patterns
    for pattern, desc in SECRET_PATTERNS:
        match = re.search(pattern, content, re.IGNORECASE | re.MULTILINE)
        if match:
            print(f"BLOCKED: {desc} detected in {file_path}", file=sys.stderr)
            print(f"Matched: {match.group(0)[:50]}...", file=sys.stderr)
            print("CLAUDE.md rule: secrets come from environment variables (process.env).", file=sys.stderr)
            print("Use process.env.API_KEY (or equivalent) and document in .env.example.", file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

